fn solve(n: i64) -> bool {
    let s = n.to_string();
    let digits: Vec<u32> = s.chars()
        .map(|c| c.to_digit(10).unwrap())
        .collect();

    let sum: u32 = digits.iter().sum();
    let product: u32 = digits.iter().fold(1, |acc, &d| acc * d);

    let sum_plus_product = sum + product;
    n % (sum_plus_product as i64) == 0
}
