fn solve(n: i64) -> bool {
    let s = n.to_string();
    let mut sum = 0;
    let mut product = 1;
    for c in s.chars() {
        let d = c.to_digit(10).unwrap();
        sum += d;
        product *= d;
    }
    let total = sum + product;
    n % total == 0
}
